#include <iostream>
#include <string>

class Shape {
public:
    std::string color;
    Shape(std::string c) : color(c) {}
};

class Circle : public Shape {
public:
    double radius;
    Circle(std::string c, double r) : Shape(c), radius(r) {}
};

class Rectangle : public Shape {
public:
    double width;
    double height;
    Rectangle(std::string c, double w, double h)
        : Shape(c), width(w), height(h) {}
};

int main() {
    Circle c{"red", 5.0};
    Rectangle r{"blue", 4.0, 3.0};

    Shape* shapes[2] = { &c, &r };

    std::cout << "Circle color: " << shapes[0]->color << "\n";
    std::cout << "Rectangle color: " << shapes[1]->color << "\n";
    return 0;
}

