#include <iostream>
#include <string>

class Animal {
public:
    std::string name;
    Animal(std::string n) : name(n) {}
};

class Cat : public Animal {
public:
    Cat(std::string n) : Animal(n) {}
};

void reportAnimal(const Animal& a) {
    std::cout << "Animal: " << a.name << "\n";
}

int main() {
    Animal a{"Buddy"};
    Cat c{"Whiskers"};
    reportAnimal(a);
    reportAnimal(c);
    return 0;
}
